 1	import React, { FC } from 'react';
 2	
 3	import {
 4	  InstanceTypeVMStore,
 5	  UseBootableVolumesValues,
 6	} from '@catalog/CreateFromInstanceTypes/state/utils/types';
 7	import { DEFAULT_PREFERENCE_LABEL } from '@catalog/CreateFromInstanceTypes/utils/constants';
 8	import { V1beta1DataSource } from '@kubevirt-ui/kubevirt-api/containerized-data-importer/models';
 9	import { V1beta1VirtualMachineClusterPreference } from '@kubevirt-ui/kubevirt-api/kubevirt';
10	import { UserSettingFavorites } from '@kubevirt-utils/hooks/useKubevirtUserSettings/utils/types';
11	import {
12	  getBootableVolumePVCSource,
13	  getDataImportCronFromDataSource,
14	} from '@kubevirt-utils/resources/bootableresources/helpers';
15	import { BootableVolume } from '@kubevirt-utils/resources/bootableresources/types';
16	import { getLabel, getName } from '@kubevirt-utils/resources/shared';
17	import { TableColumn } from '@openshift-console/dynamic-plugin-sdk';
18	import { Table, TableVariant, Tbody, Th, Thead, Tr } from '@patternfly/react-table';
19	import { ThSortType } from '@patternfly/react-table/dist/esm/components/Table/base/types';
20	
21	import BootableVolumeRow from '../BootableVolumeRow/BootableVolumeRow';
22	
23	type BootableVolumeTableProps = {
24	  activeColumns: TableColumn<BootableVolume>[];
25	  bootableVolumesData: UseBootableVolumesValues;
26	  favorites: UserSettingFavorites;
27	  getSortType: (columnIndex: number) => ThSortType;
28	  preferencesMap: {
29	    [resourceKeyName: string]: V1beta1VirtualMachineClusterPreference;
30	  };
31	  selectedBootableVolumeState?: [BootableVolume, InstanceTypeVMStore['onSelectCreatedVolume']];
32	  sortedPaginatedData: BootableVolume[];
33	};
34	
35	const BootableVolumeTable: FC<BootableVolumeTableProps> = ({
36	  activeColumns,
37	  bootableVolumesData,
38	  favorites,
39	  getSortType,
40	  preferencesMap,
41	  selectedBootableVolumeState,
42	  sortedPaginatedData,
43	}) => {
44	  const [volumeFavorites, updateFavorites] = favorites;
45	  const { dataImportCrons, pvcSources, volumeSnapshotSources } = bootableVolumesData;
46	
47	  return (
48	    <Table className="BootableVolumeList-table" variant={TableVariant.compact}>
49	      <Thead>
50	        <Tr>
51	          {activeColumns.map((col, columnIndex) => (
52	            <Th
53	              sort={
54	                columnIndex === 0
55	                  ? { ...getSortType(columnIndex), isFavorites: true }
56	                  : getSortType(columnIndex)
57	              }
58	              id={col?.id}
59	              key={col?.id}
60	            >
61	              {col?.title}
62	            </Th>
63	          ))}
64	        </Tr>
65	      </Thead>
66	      <Tbody>
67	        {sortedPaginatedData.map((bs) => (
68	          <BootableVolumeRow
69	            rowData={{
70	              bootableVolumeSelectedState: selectedBootableVolumeState,
71	              dataImportCron: getDataImportCronFromDataSource(
72	                dataImportCrons,
73	                bs as V1beta1DataSource,
74	              ),
75	              favorites: [
76	                volumeFavorites?.includes(bs?.metadata?.name),
77	                (addTofavorites: boolean) =>
78	                  updateFavorites(
79	                    addTofavorites
80	                      ? [...volumeFavorites, bs?.metadata?.name]
81	                      : volumeFavorites.filter((fav: string) => fav !== bs?.metadata?.name),
82	                  ),
83	              ],
84	              preference: preferencesMap[getLabel(bs, DEFAULT_PREFERENCE_LABEL)],
85	              pvcSource: getBootableVolumePVCSource(bs, pvcSources),
86	              volumeSnapshotSource: volumeSnapshotSources?.[bs?.metadata?.name],
87	            }}
88	            activeColumnIDs={activeColumns?.map((col) => col?.id)}
89	            bootableVolume={bs}
90	            key={getName(bs)}
91	          />
92	        ))}
93	      </Tbody>
94	    </Table>
95	  );
96	};
97	
98	export default BootableVolumeTable;

